"""Tests for hook installation merge logic."""

from scripts.install_hooks import _deep_merge, _hook_entry_key


def _relay_rule(command: str = "python3 ~/.claude/claude-dashboard/scripts/hook_relay.py"):
    """Build a hook rule entry matching the dashboard relay structure."""
    return {"hooks": [{"type": "command", "command": command}]}


class TestHookEntryKey:
    def test_returns_marker_for_relay_command(self):
        rule = _relay_rule()
        assert _hook_entry_key(rule) == ".claude/claude-dashboard/scripts/hook_relay.py"

    def test_returns_marker_with_debug_flag(self):
        rule = _relay_rule("python3 ~/.claude/claude-dashboard/scripts/hook_relay.py --debug")
        assert _hook_entry_key(rule) == ".claude/claude-dashboard/scripts/hook_relay.py"

    def test_returns_none_for_unrelated_command(self):
        rule = {"hooks": [{"type": "command", "command": "echo hello"}]}
        assert _hook_entry_key(rule) is None

    def test_returns_none_for_non_dict(self):
        assert _hook_entry_key("not a dict") is None

    def test_returns_none_for_missing_hooks_key(self):
        assert _hook_entry_key({"other": "value"}) is None


class TestDeepMergeHookReplacement:
    """Test that hook entries with changed flags replace rather than duplicate."""

    def test_replaces_relay_hook_when_flags_change(self):
        old_rule = _relay_rule("python3 ~/.claude/claude-dashboard/scripts/hook_relay.py")
        new_rule = _relay_rule("python3 ~/.claude/claude-dashboard/scripts/hook_relay.py --debug")

        dest = {"hooks": {"PreToolUse": [old_rule]}}
        src = {"hooks": {"PreToolUse": [new_rule]}}
        merged = _deep_merge(src, dest)

        assert len(merged["hooks"]["PreToolUse"]) == 1
        cmd = merged["hooks"]["PreToolUse"][0]["hooks"][0]["command"]
        assert "--debug" in cmd

    def test_preserves_unrelated_hooks(self):
        relay = _relay_rule()
        other = {"hooks": [{"type": "command", "command": "echo other"}]}

        dest = {"hooks": {"Stop": [relay, other]}}
        src = {
            "hooks": {
                "Stop": [
                    _relay_rule("python3 ~/.claude/claude-dashboard/scripts/hook_relay.py --debug")
                ]
            }
        }
        merged = _deep_merge(src, dest)

        assert len(merged["hooks"]["Stop"]) == 2
        commands = [entry["hooks"][0]["command"] for entry in merged["hooks"]["Stop"]]
        assert "echo other" in commands
        assert any("--debug" in c for c in commands)

    def test_adds_new_event_hooks(self):
        dest = {"hooks": {}}
        src = {"hooks": {"NewEvent": [_relay_rule()]}}
        merged = _deep_merge(src, dest)
        assert "NewEvent" in merged["hooks"]
        assert len(merged["hooks"]["NewEvent"]) == 1

    def test_no_duplicate_when_identical(self):
        rule = _relay_rule()
        dest = {"hooks": {"Stop": [rule]}}
        src = {"hooks": {"Stop": [rule]}}
        merged = _deep_merge(src, dest)
        assert len(merged["hooks"]["Stop"]) == 1

    def test_preserves_dest_only_events(self):
        dest = {"hooks": {"CustomEvent": [{"hooks": [{"type": "command", "command": "foo"}]}]}}
        src = {"hooks": {"Stop": [_relay_rule()]}}
        merged = _deep_merge(src, dest)
        assert "CustomEvent" in merged["hooks"]
        assert "Stop" in merged["hooks"]
